CREATE TABLE IF NOT EXISTS governance_committees (id BIGSERIAL PRIMARY KEY, name VARCHAR(150) NOT NULL, scope VARCHAR(120) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'ACTIVE');
CREATE TABLE IF NOT EXISTS governance_policies (id BIGSERIAL PRIMARY KEY, title VARCHAR(180) NOT NULL, code VARCHAR(60) NOT NULL UNIQUE, owner VARCHAR(120) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'DRAFT');
CREATE TABLE IF NOT EXISTS governance_policy_versions (id BIGSERIAL PRIMARY KEY, policy_id BIGINT NOT NULL REFERENCES governance_policies(id), version VARCHAR(20) NOT NULL, content TEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS governance_approvals (id BIGSERIAL PRIMARY KEY, policy_id BIGINT NULL REFERENCES governance_policies(id), approval_level VARCHAR(60) NOT NULL, approver VARCHAR(120) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'PENDING');
CREATE TABLE IF NOT EXISTS approval_levels (id BIGSERIAL PRIMARY KEY, name VARCHAR(80) NOT NULL, max_amount NUMERIC(14,2) NULL);
CREATE TABLE IF NOT EXISTS responsibility_matrix (id BIGSERIAL PRIMARY KEY, process_name VARCHAR(120) NOT NULL, responsible VARCHAR(120) NOT NULL, accountable VARCHAR(120) NOT NULL, consulted VARCHAR(120) NULL, informed VARCHAR(120) NULL);
CREATE TABLE IF NOT EXISTS governance_decisions (id BIGSERIAL PRIMARY KEY, committee_id BIGINT REFERENCES governance_committees(id), decision_text TEXT NOT NULL, decided_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS meeting_minutes (id BIGSERIAL PRIMARY KEY, committee_id BIGINT REFERENCES governance_committees(id), meeting_date DATE NOT NULL, notes TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS corporate_risks (id BIGSERIAL PRIMARY KEY, risk_name VARCHAR(180) NOT NULL, impact VARCHAR(20) NOT NULL, probability VARCHAR(20) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'OPEN');
CREATE TABLE IF NOT EXISTS internal_controls (id BIGSERIAL PRIMARY KEY, control_name VARCHAR(160) NOT NULL, owner VARCHAR(120) NOT NULL, frequency VARCHAR(40) NOT NULL);
CREATE TABLE IF NOT EXISTS control_evidences (id BIGSERIAL PRIMARY KEY, control_id BIGINT NOT NULL REFERENCES internal_controls(id), evidence_url TEXT NULL, details TEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS governance_action_plans (id BIGSERIAL PRIMARY KEY, decision_id BIGINT NULL REFERENCES governance_decisions(id), action_name VARCHAR(180) NOT NULL, owner VARCHAR(120) NOT NULL, due_date DATE NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'OPEN');
